#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;cin>>n>>m;vector<string>g(n);for(auto&s:g)cin>>s;int best=1e9;for(int i=0;i+8<=n;i++)for(int j=0;j+8<=m;j++){int cw=0;for(int x=0;x<8;x++)for(int y=0;y<8;y++){char want=((x+y)%2==0)?'W':'B';if(g[i+x][j+y]!=want)cw++;}best=min(best,min(cw,64-cw));}cout<<best<<"\n";}
